const apiKey = $vars.N8N_INTERNAL_API_KEY;
const host = 'https://mmurawala.app.n8n.cloud';
const headers = {'X-N8N-API-KEY': apiKey, 'Content-Type': 'application/json'};
let workflows = [];
try {
  const wfRes = await this.helpers.httpRequest({method: 'GET', url: host + '/api/v1/workflows?limit=250&active=true', headers, json: true});
  workflows = wfRes.data || [];
} catch(e) { workflows = [{error: e.message}]; }
let changelog = [];
try {
  const clRes = await this.helpers.httpRequest({method: 'GET', url: host + '/api/v1/data-tables/kqKrSqKSsu8UbU89/rows?limit=20', headers, json: true});
  changelog = (clRes.data || []).slice(0, 10);
} catch(e) { changelog = [{error: e.message}]; }
let errors = [];
try {
  const exRes = await this.helpers.httpRequest({method: 'GET', url: host + '/api/v1/executions?status=error&limit=20', headers, json: true});
  errors = (exRes.data || []).map(e => ({id: e.id, workflowName: (e.workflowData||{}).name, stoppedAt: e.stoppedAt}));
} catch(e) { errors = [{error: e.message}]; }
let credHealth = [];
try {
  const crRes = await this.helpers.httpRequest({method: 'GET', url: host + '/api/v1/data-tables/wCfdPfENLbe1jvc2/rows?limit=50', headers, json: true});
  credHealth = crRes.data || [];
} catch(e) { credHealth = [{error: e.message}]; }
return [{json: {
  timestamp: new Date().toISOString(),
  active_workflow_count: workflows.length,
  active_workflows: workflows.map(w => ({id: w.id, name: w.name, updatedAt: w.updatedAt})),
  recent_changelog: changelog,
  recent_errors: errors,
  credential_health: credHealth
}}];

const state = $input.first().json;
const token = $vars.HINDSIGHT_MCP_TOKEN;
const bankId = 'ascend-infra';
const url = 'https://hindsight.ascendgtm.net/v1/default/banks/' + bankId + '/memories';
const ts = state.timestamp;
const wfCount = state.active_workflow_count;
const errorCount = (state.recent_errors || []).length;
const topWfs = (state.active_workflows || []).sort((a,b) => (b.updatedAt||'').localeCompare(a.updatedAt||'')).slice(0, 20).map(w => w.name + ' (' + w.id + ')').join(', ');
const errorSummary = errorCount === 0 ? 'No execution errors in last 24h.' : (state.recent_errors || []).map(e => (e.workflowName || 'unknown')).join('; ');
const clSummary = (state.recent_changelog || []).length === 0 ? 'No recent changelog entries.' : (state.recent_changelog || []).slice(0, 5).map(c => (c.category || '') + '/' + (c.domain || '') + ': ' + (c.summary || '')).join('; ');
const credSummary = (state.credential_health || []).length === 0 ? 'No credential health data.' : 'Credentials tracked: ' + (state.credential_health || []).length;
const items = [{content: 'Platform Sync ' + ts + ' | ' + wfCount + ' active workflows, ' + errorCount + ' recent errors. Errors: ' + errorSummary + ' | Changelog: ' + clSummary + ' | Credentials: ' + credSummary + ' | Recently updated workflows: ' + topWfs}];
try {
  const res = await this.helpers.httpRequest({method: 'POST', url: url, headers: {'Authorization': 'Bearer ' + token, 'Content-Type': 'application/json'}, body: JSON.stringify({items: items, async: true})});
  return [{json: {success: true, bank_id: bankId, items_count: items.length, timestamp: ts}}];
} catch(e) {
  return [{json: {success: false, error: e.message, bank_id: bankId, timestamp: ts}}];
}

const input = $input.first().json;
const host = 'https://mmurawala.app.n8n.cloud';
const apiKey = $vars.N8N_INTERNAL_API_KEY;
try {
  await this.helpers.httpRequest({method: 'POST', url: host + '/api/v1/data-tables/PLh0y2lR6CWkZ88y/rows', headers: {'X-N8N-API-KEY': apiKey, 'Content-Type': 'application/json'}, body: JSON.stringify({data: [{severity: 'warning', source: 'PLATFORM_MEMORY_SYNC', message: 'Memory sync failed: ' + (input.error || 'unknown'), timestamp: new Date().toISOString()}]})});
} catch(e) {}
return [{json: {alerted: true, original_error: input.error}}];
